diff --git a/llvm/lib/Transforms/InstCombine/InstCombineCalls.cpp b/llvm/lib/Transforms/InstCombine/InstCombineCalls.cpp
index 33b66aeaffe6..a4436fd78b93 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineCalls.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineCalls.cpp
@@ -2901,6 +2901,16 @@ Instruction *InstCombinerImpl::visitCallInst(CallInst &CI) {
         CallInst *Fabs = Builder.CreateUnaryIntrinsic(Intrinsic::fabs, X, II);
         return replaceInstUsesWith(CI, Fabs);
     }
+    // fabs (X + 0.0) --> fabs X
+    // fabs (0.0 + X) --> fabs X
+    // fabs (X - 0.0) --> fabs X
+    if (Arg->hasOneUse() &&
+        (match(Arg, m_FAdd(m_Value(X), m_AnyZeroFP())) ||
+         match(Arg, m_FAdd(m_AnyZeroFP(), m_Value(X))) ||
+         match(Arg, m_FSub(m_Value(X), m_AnyZeroFP())))) {
+      CallInst *Fabs = Builder.CreateUnaryIntrinsic(Intrinsic::fabs, X, II);
+      return replaceInstUsesWith(CI, Fabs);
+    }

